// export default AftBankTransfer;
import React, { useState, useEffect } from "react";
import {
  Button,
  Card,
  CircularProgress,
  Typography,
  TextField,
  Box,
  InputAdornment,
} from "@mui/material";
import { toast } from "react-toastify";
import { aftBankTransfer } from "../../api/login/Login";
import AftPageLayout from "./AftPageLayout";
import { motion } from "framer-motion";
import airtelBank from "../../asesets/bill-payments/airtelbank.png";
// Match the existing pattern used in SimStore / SimReplacement / PortNumber
// — swap this path if your actual asset filename differs.
const AIRTEL_LOGO_URL =
  "https://commons.wikimedia.org/wiki/Special:FilePath/Bharti_Airtel_Logo.svg";


/* ---------- Airtel-brand accent (used only as color, never as logo
   artwork — the backdrop below is an original abstract pattern, not a
   reproduction of any Airtel mark) ---------- */
const RED = "#ED1C24";
const RED_DARK = "#C4141B";
const RED_TINT = "#FFF1F1";
const INK = "#1B2430";
const MUTED = "#6B7684";
const LINE = "#EBEDF0";

const STEPS = [
  { icon: "phone", label: "Enter number" },
  { icon: "shield", label: "Verify" },
  { icon: "check", label: "Transferred" },
];

const AftBankTransfer = () => {
  const [mobileNumber, setMobile] = useState("");
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(false);
  const [isMobile, setIsMobile] = useState(
    typeof window !== "undefined" ? window.innerWidth < 900 : false
  );

  useEffect(() => {
    const savedMobile = localStorage.getItem("mobileNumber")?.slice(-10);
    if (savedMobile) setMobile(savedMobile);
  }, []);

  useEffect(() => {
    const onResize = () => setIsMobile(window.innerWidth < 900);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  useEffect(() => {
    const { body, documentElement: html } = document;
    const prevBodyOverflow = body.style.overflow;
    const prevHtmlOverflow = html.style.overflow;
    const prevBodyHeight = body.style.height;
    const prevHtmlHeight = html.style.height;

    body.style.overflow = "hidden";
    html.style.overflow = "hidden";
    body.style.height = "100%";
    html.style.height = "100%";

    return () => {
      body.style.overflow = prevBodyOverflow;
      html.style.overflow = prevHtmlOverflow;
      body.style.height = prevBodyHeight;
      html.style.height = prevHtmlHeight;
    };
  }, []);

  const handleSubmit = async () => {
    if (!/^[6-9]\d{9}$/.test(mobileNumber)) {
      toast.error("Enter valid 10 digit mobile number");
      return;
    }

    setLoading(true);
    localStorage.setItem("mobileNumber", mobileNumber);

    try {
      const res = await aftBankTransfer({ mobileNumber });
      const response = res?.data;

      if (response?.statuscode === "GRU") {
        window.location.href = response?.data?.abRedirectUrl;
        return;
      }

      if (response?.error === false) {
        toast.success(response?.status || "Success");
      } else {
        toast.error(response?.status || "AFT Failed");
      }
    } catch (error) {
      toast.error(error?.response?.data?.message || "AFT request failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AftPageLayout title="AFT Bank Transfer">
      <Box
        sx={{
          position: "fixed",
          inset: 0,
          overflow: "hidden",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          px: 2,
          background: `radial-gradient(circle at 12% 10%, ${RED}22 0%, transparent 42%),
                        radial-gradient(circle at 92% 88%, ${RED}1a 0%, transparent 48%),
                        #FDFDFD`,
        }}
      >
        {/* light dot-grid + faint signal-wave motif, full viewport */}
        <Box sx={{ position: "absolute", inset: 0, zIndex: 0, pointerEvents: "none" }}>
          <svg width="100%" height="100%" style={{ position: "absolute", inset: 0 }}>
            <defs>
              <pattern id="dotGrid" width="26" height="26" patternUnits="userSpaceOnUse">
                <circle cx="1.4" cy="1.4" r="1.4" fill={RED} opacity="0.09" />
              </pattern>
              <linearGradient id="arcFade" x1="0" y1="0" x2="1" y2="1">
                <stop offset="0%" stopColor={RED} stopOpacity="0.28" />
                <stop offset="100%" stopColor={RED} stopOpacity="0" />
              </linearGradient>
            </defs>
            <rect width="100%" height="100%" fill="url(#dotGrid)" />
            {[110, 175, 240, 305].map((r) => (
              <circle
                key={r}
                cx="92%"
                cy="8%"
                r={r}
                stroke={RED}
                strokeOpacity={0.12}
                strokeWidth="1.5"
                fill="none"
              />
            ))}
            <path d="M -50 620 Q 400 420 900 640" stroke="url(#arcFade)" strokeWidth="2" fill="none" />
            <path d="M -80 720 Q 420 560 960 760" stroke="url(#arcFade)" strokeWidth="1.5" fill="none" />
          </svg>
        </Box>


{/* Airtel Bank logo — top-left corner of the page */}
{/* Airtel Bank logo — top-left corner of the page, fully visible & larger */}
<Box
  component="img"
  src={airtelBank}
  alt="Airtel Payments Bank"
  sx={{
    position: "fixed",
    top: { xs: 24, md: 40 },
    left: { xs: 24, md: 40 },
    width: { xs: 140, md: 220 },
    height: "auto",
    zIndex: 4,
    objectFit: "contain",
  }}
/>
        {/* ---- main row: big logo (left) + card (right) ---- */}
        <Box
          sx={{
            position: "relative",
            zIndex: 1,
            display: "flex",
            flexDirection: isMobile ? "column" : "row",
            alignItems: "center",
            justifyContent: "center",
            gap: { xs: 3, md: 6 },
            width: "100%",
            maxWidth: 920,
          }}
        >
        {/* ---- big Airtel logo panel ---- */}
{/* ---- big Airtel logo, floating slowly across the whole screen ---- */}
{/* ---- big Airtel logo, drifting in a slow circular path, always on-screen ---- */}
<motion.div
  style={{
    position: "fixed",
    top: "50%",
    left: "50%",
    zIndex: 1,
    pointerEvents: "none",
  }}
  animate={{
    x: [
      "-30vw", "-42vw", "-30vw", "0vw", "30vw", "42vw", "30vw", "0vw", "-30vw",
    ],
    y: [
      "0vh", "-25vh", "-35vh", "-25vh", "0vh", "25vh", "35vh", "25vh", "0vh",
    ],
  }}
  transition={{
    duration: 30,
    repeat: Infinity,
    ease: "linear",
    times: [0, 0.125, 0.25, 0.375, 0.5, 0.625, 0.75, 0.875, 1],
  }}
>
  <Box
    sx={{
      width: { xs: 90, md: 180 },
      height: { xs: 90, md: 180 },
      borderRadius: "50%",
      background: "#fff",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      boxShadow: `0 20px 50px ${RED}25`,
      p: { xs: 2, md: 3 },
      transform: "translate(-50%, -50%)",
    }}
  >
    <Box
      component="img"
      src={AIRTEL_LOGO_URL}
      alt="Airtel"
      sx={{ width: "100%", height: "100%", objectFit: "contain" }}
    />
  </Box>
</motion.div>

{/* ---- form card, centered in the middle of the screen ---- */}
<motion.div
  initial={{ opacity: 0, y: 14 }}
  animate={{ opacity: 1, y: 0 }}
  transition={{ duration: 0.35, ease: "easeOut" }}
  style={{
    width: "100%",
    maxWidth: 460,
    position: "relative",
    zIndex: 10,
  }}
>
  {/* circular logo, overlapping the card's top-left edge */}
  

 <Card
  sx={{
    borderRadius: "22px",
    border: `1px solid ${LINE}`,
    boxShadow: "0 24px 60px rgba(0,0,0,0.35)",
    overflow: "hidden",
    background: "#fff",
    p: { xs: 2.5, sm: 3.25 },
    maxHeight: "92vh",
    display: "flex",
    flexDirection: "column",
    gap: { xs: 1.4, sm: 1.7 },
  }}
>
              <Box sx={{ display: "flex", alignItems: "center", gap: 1.2 }}>
                <Box
                  sx={{
                    width: 40,
                    height: 40,
                    borderRadius: "12px",
                    flexShrink: 0,
                    background: `linear-gradient(135deg, ${RED}, ${RED_DARK})`,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    boxShadow: `0 8px 18px ${RED}40`,
                  }}
                >
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.2">
                    <path d="M4 12a8 8 0 0 1 16 0" />
                    <path d="M7.5 12a4.5 4.5 0 0 1 9 0" />
                    <circle cx="12" cy="16.5" r="1.4" fill="#fff" stroke="none" />
                  </svg>
                </Box>
                <Box>
                  <Typography sx={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: 10.5, letterSpacing: 1.4, color: RED, fontWeight: 700 }}>
                    AIRTEL PAYMENTS BANK
                  </Typography>
                  <Typography sx={{ fontFamily: "'Plus Jakarta Sans', sans-serif", fontWeight: 800, fontSize: 17, color: INK, lineHeight: 1.2 }}>
                    Auto Fund Transfer
                  </Typography>
                </Box>
              </Box>

              <Box sx={{ display: "flex", alignItems: "center" }}>
                {STEPS.map((step, i) => (
                  <React.Fragment key={step.label}>
                    <Box sx={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 0.5, minWidth: 0 }}>
                      <Box
                        sx={{
                          width: 26,
                          height: 26,
                          borderRadius: "50%",
                          background: i === 0 ? RED_TINT : "#F4F5F6",
                          border: `1.4px solid ${i === 0 ? RED : "#D8DBDF"}`,
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          flexShrink: 0,
                        }}
                      >
                        <StepIcon type={step.icon} active={i === 0} />
                      </Box>
                      <Typography sx={{ fontSize: 9.5, color: i === 0 ? RED_DARK : MUTED, fontWeight: 600, textAlign: "center" }}>
                        {step.label}
                      </Typography>
                    </Box>
                    {i < STEPS.length - 1 && (
                      <Box sx={{ flex: 1, height: "1.4px", background: "#E4E6E9", mx: 0.5, mb: 1.6 }} />
                    )}
                  </React.Fragment>
                ))}
              </Box>

              <Typography sx={{ fontSize: 12.5, color: MUTED, lineHeight: 1.5 }}>
                Enter the Airtel number registered with your Airtel Payments Bank account.
              </Typography>

              <TextField
                fullWidth
                className="mui-autofill-fix"
                placeholder="98765 43210"
                value={mobileNumber}
                onChange={(e) => setMobile(e.target.value.replace(/\D/g, "").slice(0, 10))}
                onFocus={() => setFocused(true)}
                onBlur={() => setFocused(false)}
                inputProps={{ maxLength: 10, style: { fontSize: 16, letterSpacing: 0.4 } }}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Typography sx={{ fontSize: 14.5, color: RED_DARK, fontWeight: 700 }}>+91</Typography>
                      <Box sx={{ width: "1px", height: 18, background: "#E4E6E9", mx: 1.2 }} />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  "& .MuiOutlinedInput-root": {
                    borderRadius: "10px",
                    background: "#FAFAFA",
                    "& fieldset": { borderColor: focused ? RED : "#DDE0E3" },
                    "&:hover fieldset": { borderColor: RED },
                    "&.Mui-focused fieldset": { borderColor: RED, borderWidth: "1.5px" },
                  },
                }}
              />

              <Box
                sx={{
                  background: RED_TINT,
                  borderLeft: `3px solid ${RED}`,
                  borderRadius: "0 8px 8px 0",
                  p: 1.3,
                }}
              >
                <Typography sx={{ fontSize: 11.5, color: RED_DARK, lineHeight: 1.45 }}>
                  <b>Note:</b> Use only the Airtel mobile number linked to Airtel Payments Bank.
                </Typography>
                <Typography sx={{ fontSize: 10.5, mt: 0.4, color: "#B24A4E", lineHeight: 1.45 }}>
                  नोट: कृपया वही एयरटेल मोबाइल नंबर दर्ज करें जो एयरटेल पेमेंट्स बैंक से पंजीकृत हो।
                </Typography>
              </Box>

              <Button
                fullWidth
                disableElevation
                disabled={loading}
                onClick={handleSubmit}
                sx={{
                  py: 1.3,
                  borderRadius: "10px",
                  fontWeight: 700,
                  fontSize: 15,
                  textTransform: "none",
                  background: `linear-gradient(135deg, ${RED}, ${RED_DARK})`,
                  color: "#fff",
                  "&:hover": { background: RED_DARK },
                  "&.Mui-disabled": { color: "#fff", opacity: 0.6 },
                }}
              >
                {loading ? <CircularProgress size={22} sx={{ color: "#fff" }} /> : "Submit AFT"}
              </Button>

              <Box sx={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 0.7 }}>
                <Box sx={{ width: 6, height: 6, borderRadius: "50%", background: RED }} />
                <Typography sx={{ fontSize: 10.5, color: MUTED, fontWeight: 600 }}>
                  Secured by Airtel Payments Bank · RBI licensed
                </Typography>
              </Box>
            </Card>
          </motion.div>
        </Box>
      </Box>
    </AftPageLayout>
  );
};

const StepIcon = ({ type, active }) => {
  const stroke = active ? "#ED1C24" : "#9AA0A6";
  if (type === "phone")
    return (
      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={stroke} strokeWidth="2.4">
        <rect x="7" y="2" width="10" height="20" rx="2" />
        <line x1="11" y1="18" x2="13" y2="18" />
      </svg>
    );
  if (type === "shield")
    return (
      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={stroke} strokeWidth="2.4">
        <path d="M12 2 4 5v6c0 5 3.4 9 8 11 4.6-2 8-6 8-11V5l-8-3z" />
      </svg>
    );
  return (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={stroke} strokeWidth="2.8">
      <path d="M4 12l5 5 11-11" />
    </svg>
  );
};

export default AftBankTransfer;